import{d as e}from"./app.e7543a9d.js";import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";const r={},i=e('<h1 id="firing" tabindex="-1"><a class="header-anchor" href="#firing" aria-hidden="true">#</a> Firing</h1><p>Often, glaze recipes are intended for a specific firing atmosphere. Glazes like Celadon and Copper Red require a <em>reduction atmosphere</em> in order to achieve the intended blue/green or red color for those glazes. Other glazes like clears and whites might look the same whether they are fired in oxidation or reduction.</p><p>Some recipes like flashing slips and luster glazes are specifically designed to give special effects in <strong>wood</strong>, <strong>salt &amp; soda</strong>, or <strong>raku</strong> firings.</p><h2 id="firing-atmosphere" tabindex="-1"><a class="header-anchor" href="#firing-atmosphere" aria-hidden="true">#</a> Firing Atmosphere</h2><h3 id="oxidation" tabindex="-1"><a class="header-anchor" href="#oxidation" aria-hidden="true">#</a> Oxidation</h3><h3 id="neutral" tabindex="-1"><a class="header-anchor" href="#neutral" aria-hidden="true">#</a> Neutral</h3><h3 id="reduction" tabindex="-1"><a class="header-anchor" href="#reduction" aria-hidden="true">#</a> Reduction</h3><h3 id="salt-soda" tabindex="-1"><a class="header-anchor" href="#salt-soda" aria-hidden="true">#</a> Salt &amp; Soda</h3><h3 id="wood" tabindex="-1"><a class="header-anchor" href="#wood" aria-hidden="true">#</a> Wood</h3><h3 id="raku" tabindex="-1"><a class="header-anchor" href="#raku" aria-hidden="true">#</a> Raku</h3><h3 id="luster" tabindex="-1"><a class="header-anchor" href="#luster" aria-hidden="true">#</a> Luster</h3>',11);function d(t,n){return i}var s=a(r,[["render",d]]);export{s as default};
